/* =========================================
   iOS 短信界面 (Card 1, 2, 3)
   ========================================= */
.xt-card {
    background: #fff; padding: 0; border: 1px solid #E5E5E5; margin-bottom: 25px;
    overflow: hidden; box-shadow: 0 4px 15px rgba(0,0,0,0.05); position: relative; border-radius: 16px; padding-top: 45px;
