.xt-card .xt-card-title { display: none; } 

/* iOS 顶栏 */
.xt-card::before {
    position: absolute; top: 0; left: 0; right: 0; height: 45px;
    background: #F7F7F7; border-bottom: 1px solid #E5E5E5;
